import base64
import zlib

def unpack_pob(pob_string):
    # Convert base64url to base64 and decode
    decoded = base64.urlsafe_b64decode(pob_string + '==')  # Adds padding if needed
    # Decompress
    xml = zlib.decompress(decoded).decode('utf-8')
    return xml

